// Usage: node scripts/generate-crm-tracker.js
// Output: reports/客户管理看板_{date}.xlsx

const fs = require('fs');
const path = require('path');
const ExcelJS = require('exceljs');

const DATA_DIR = path.join(__dirname, '..', 'data');
const REPORTS_DIR = path.join(__dirname, '..', 'reports');
const TM_FILE = path.join(DATA_DIR, 'tm_conversations_latest.json');
const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
const CUSTOMERS_DIR = path.join(DATA_DIR, 'customers');
const STATE_FILE = path.join(__dirname, '..', 'STATE.md');

// Config
const NOW = new Date();
const DATE_STR = NOW.toISOString().slice(0, 10);
const NOW_TS = NOW.getTime();
const DAY_MS = 24 * 60 * 60 * 1000;

// Helpers
function daysAgo(ts) {
  if (!ts) return '—';
  return Math.floor((NOW_TS - ts) / DAY_MS);
}
function fmtDate(ts) {
  if (!ts) return '—';
  return new Date(ts).toISOString().slice(0, 10);
}
function cidToFilename(cid) {
  return cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : null;
}

// === MAIN ===
console.log('[CRM Tracker] Reading data...');

// 1. Read conversations
if (!fs.existsSync(TM_FILE)) { console.error('tm_conversations_latest.json not found'); process.exit(1); }
const tmData = JSON.parse(fs.readFileSync(TM_FILE, 'utf8'));
const convs = tmData.conversations || [];
console.log(`  ${convs.length} conversations`);

// 2. Read customers index (lazy load)
const customerFiles = fs.readdirSync(CUSTOMERS_DIR).filter(f => f.endsWith('.json'));
console.log(`  ${customerFiles.length} customer profiles`);

// Build a quick customer lookup: aliId → customer data (light fields only)
const custLookup = {};
for (const f of customerFiles) {
  try {
    const raw = fs.readFileSync(path.join(CUSTOMERS_DIR, f), 'utf8');
    const cust = JSON.parse(raw);
    const aliId = cust.listData?.source?.includes('阿里巴巴') && cust.detail?.alibaba_info
      ? Object.keys(cust.detail.alibaba_info)[0] : null;
    // Store by company_id as primary key, also by aliId if available
    const entry = {
      okkiLevel: cust.listData?.level || '',
      okkiStatus: cust.listData?.status || '',
      country: cust.detail?.country || cust.listData?.country || '',
      score: cust.listData?.score || 0,
      orderCount: cust.listData?.orderCount || 0,
      orderAmount: cust.listData?.orderAmount || '0',
      intent: cust.detail?.intention_level_info || '',
      annualProcurement: cust.detail?.annual_procurement_info || '',
      latestTMReceive: cust.detail?.latest_receive_ali_tm_time_info || '',
      latestTMSend: cust.detail?.latest_send_ali_tm_time_info || '',
    };
    custLookup[cust.company_id] = entry;
  } catch (e) { /* skip broken files */ }
}

// 3. Read chat_history for message counts (cached)
const chatFiles = new Set(fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json')));
// Quick lookup: filename → totalMessages (read first 200 bytes only for speed)
const chatMsgCount = {};
for (const cf of chatFiles) {
  try {
    const raw = fs.readFileSync(path.join(CHAT_DIR, cf), 'utf8');
    const match = raw.match(/"totalMessages":\s*(\d+)/);
    if (match) chatMsgCount[cf] = parseInt(match[1]);
  } catch (e) { /* skip */ }
}
console.log(`  ${Object.keys(chatMsgCount).length} chat histories with msg counts`);

// 4. Parse existing tier assignments from STATE.md
const tierMap = {};
if (fs.existsSync(STATE_FILE)) {
  const stateContent = fs.readFileSync(STATE_FILE, 'utf8');
  // Extract P0-P4 assignments from table
  const tierSection = stateContent.match(/\|\s*\*\*P\d\*\*[^\n]*\n/g);
  if (tierSection) {
    for (const line of tierSection) {
      const tierMatch = line.match(/\*\*(P\d)\*\*\s+\S+\s+\|\s+\*?\*?(\d+)\*?\*?\s*\|?\s*(.+)/);
      if (tierMatch) {
        const tier = tierMatch[1];
        const names = tierMatch[3].split(/[,，、]/);
        for (const name of names) {
          const trimmed = name.trim();
          if (trimmed && !trimmed.startsWith('等') && !trimmed.match(/^\d+/)) {
            tierMap[trimmed.toLowerCase()] = tier;
          }
        }
      }
    }
  }
}

// 5. Build rows
const rows = [];
for (const conv of convs) {
  const filename = cidToFilename(conv.cid);
  const msgCount = filename ? (chatMsgCount[filename] || 0) : 0;
  const lastDays = daysAgo(conv.lastContactTime);
  const aliId = conv.aliId ? String(conv.aliId) : null;

  // Match with customer data
  let custInfo = null;
  // Try direct match by aliId in alibaba_info keys
  if (aliId) {
    for (const [companyId, info] of Object.entries(custLookup)) {
      // This is approximate — customer profiles don't have a direct cid/aliId key
      // We'll match by name later if needed
    }
  }
  // Fallback: no reliable cross-reference between tm_conversations and customers without deeper matching
  // We'll leave OKKI fields blank for now and fill via AI analysis

  // Determine tier
  const nameLower = (conv.name || '').toLowerCase();
  let tier = '';
  for (const [key, val] of Object.entries(tierMap)) {
    if (nameLower.includes(key) || key.includes(nameLower)) {
      tier = val;
      break;
    }
  }

  // Determine message direction
  let lastMsgDir = '';
  if (conv.latestMessage) {
    lastMsgDir = conv.latestMessage.messageType === 'send' ? '我方' : '客户';
  }

  rows.push({
    name: conv.name || '',
    country: conv.complianceCountryCode || '',
    cid: conv.cid,
    tier,
    lastContactDays: lastDays,
    lastContactDate: fmtDate(conv.lastContactTime),
    msgCount,
    lastMsgDir,
    unreadCount: conv.unreadCount || 0,
    filename: filename || '',
    aliId: aliId || '',
    // Blank fields for AI to fill
    stage: '',
    bottleneck: '',
    nextAction: '',
    priority: '',
    notes: '',
  });
}

// Sort: by lastContactDays asc (most recent first)
rows.sort((a, b) => a.lastContactDays - b.lastContactDays);

// === GENERATE EXCEL ===
console.log('[CRM Tracker] Generating Excel...');

const wb = new ExcelJS.Workbook();
wb.creator = 'OKKI CRM Tracker';
wb.created = NOW;

const ws = wb.addWorksheet('客户管理看板', {
  views: [{ state: 'frozen', ySplit: 1 }],
});

// Column definitions
const columns = [
  { header: '客户名', key: 'name', width: 24 },
  { header: '国家', key: 'country', width: 8 },
  { header: '梯队', key: 'tier', width: 6 },
  { header: '最后联系(天)', key: 'lastContactDays', width: 12 },
  { header: '最后联系日期', key: 'lastContactDate', width: 14 },
  { header: '总消息数', key: 'msgCount', width: 10 },
  { header: '最新消息', key: 'lastMsgDir', width: 10 },
  { header: '未读数', key: 'unreadCount', width: 8 },
  { header: '沟通阶段', key: 'stage', width: 16 },
  { header: '卡点', key: 'bottleneck', width: 24 },
  { header: '下一步行动', key: 'nextAction', width: 30 },
  { header: '优先级', key: 'priority', width: 8 },
  { header: '备注', key: 'notes', width: 20 },
  { header: 'CID', key: 'cid', width: 36 },
  { header: '聊天文件', key: 'filename', width: 42 },
];

ws.columns = columns;

// Header style
const headerRow = ws.getRow(1);
headerRow.font = { bold: true, size: 11, color: { argb: 'FFFFFFFF' } };
headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
headerRow.alignment = { vertical: 'middle', horizontal: 'center' };
headerRow.height = 24;

// Tier colors
const tierColors = {
  'P0': { argb: 'FFC00000' },  // Red
  'P1': { argb: 'FFED7D31' },  // Orange
  'P2': { argb: 'FFFFC000' },  // Yellow
  'P3': { argb: 'FF4472C4' },  // Blue
  'P4': { argb: 'FFA5A5A5' },  // Gray
};

// Data rows
for (const row of rows) {
  const r = ws.addRow(row);
  r.height = 20;

  // Color tier cell
  if (row.tier && tierColors[row.tier]) {
    const tierCell = r.getCell('tier');
    tierCell.font = { bold: true, color: { argb: 'FFFFFFFF' } };
    tierCell.fill = { type: 'pattern', pattern: 'solid', fgColor: tierColors[row.tier] };
    tierCell.alignment = { horizontal: 'center' };
  }

  // Style stage/bottleneck cells for empty detection
  if (row.stage) {
    r.getCell('stage').font = { bold: true };
  }
  if (row.bottleneck) {
    r.getCell('bottleneck').font = { color: { argb: 'FFC00000' } };
  }

  // Dim rows with very old contact
  if (row.lastContactDays > 30) {
    r.font = { color: { argb: 'FFA0A0A0' } };
  }

  // Highlight unread
  if (row.unreadCount > 0) {
    r.getCell('unreadCount').font = { bold: true, color: { argb: 'FFC00000' } };
  }
}

// Auto-filter
ws.autoFilter = {
  from: { row: 1, column: 1 },
  to: { row: rows.length + 1, column: columns.length },
};

// Add summary sheet
const summaryWs = wb.addWorksheet('统计');
summaryWs.columns = [
  { header: '指标', key: 'metric', width: 20 },
  { header: '数值', key: 'value', width: 20 },
];

const tierCounts = { P0: 0, P1: 0, P2: 0, P3: 0, P4: 0, '未分类': 0 };
for (const row of rows) {
  if (row.tier && tierCounts[row.tier] !== undefined) tierCounts[row.tier]++;
  else tierCounts['未分类']++;
}

const active24h = rows.filter(r => r.lastContactDays < 1).length;
const active7d = rows.filter(r => r.lastContactDays < 7).length;
const active30d = rows.filter(r => r.lastContactDays < 30).length;
const silence30d = rows.filter(r => r.lastContactDays >= 30).length;
const withStage = rows.filter(r => r.stage).length;
const withBottleneck = rows.filter(r => r.bottleneck).length;

summaryWs.addRows([
  { metric: '生成时间', value: NOW.toISOString().slice(0, 16).replace('T', ' ') },
  { metric: '客户总数', value: rows.length },
  { metric: '24h活跃', value: active24h },
  { metric: '7d活跃', value: active7d },
  { metric: '30d活跃', value: active30d },
  { metric: '>30d沉默', value: silence30d },
  { metric: '', value: '' },
  ...Object.entries(tierCounts).map(([k, v]) => ({ metric: `梯队 ${k}`, value: v })),
  { metric: '', value: '' },
  { metric: '已标注阶段', value: withStage },
  { metric: '已标注卡点', value: withBottleneck },
  { metric: '待AI分析', value: rows.length - withStage },
]);

summaryWs.getRow(1).font = { bold: true };
summaryWs.getRow(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
summaryWs.getRow(1).font = { bold: true, color: { argb: 'FFFFFFFF' } };

// Save
const outFile = path.join(REPORTS_DIR, `客户管理看板_${DATE_STR}.xlsx`);
if (!fs.existsSync(REPORTS_DIR)) fs.mkdirSync(REPORTS_DIR, { recursive: true });
await wb.xlsx.writeFile(outFile);
console.log(`[CRM Tracker] Done: ${outFile}`);
console.log(`  ${rows.length} customers | P0:${tierCounts.P0} P1:${tierCounts.P1} P2:${tierCounts.P2} P3:${tierCounts.P3} P4:${tierCounts.P4}`);
console.log(`  Active: 24h:${active24h} 7d:${active7d} 30d:${active30d} | Silent:${silence30d}`);
