file.content:
const fs = require('fs');
const path = require('path');

const dataPath = path.join(__dirname, '..', 'data', 'tm_conversations_latest.json');
const data = JSON.parse(fs.readFileSync(dataPath, 'utf8'));
const now = Date.now();
const DAY = 86400000;

// System message patterns to filter
const sysPatterns = [
  '自动接待将不再触发', 'Since you have read the conversation',
  'Marco大模型翻译', '阿里国际Marco大模型翻译',
  '买家有流失风险', 'Buyer has churn risk',
  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
  '反馈', 'AI给您生成了一条回复建议',
  'You have a visitor', 'This buyer has been pre-screened',
];

function isSystemMsg(content) {
  if (!content) return true;
  for (const p of sysPatterns) {
    if (content.includes(p)) return true;
  }
  return false;
}

function classify(conv) {
  const lastContact = conv.lastContactTime || 0;
  const daysAgo = Math.round((now - lastContact) / DAY);
  const isUnread = conv.unreadCount > 0;
  const latestContent = conv.latestMessage?.content || '';
  const latestType = conv.latestMessage?.messageType || '';
  const country = conv.complianceCountryCode || '';
  const isSys = isSystemMsg(latestContent);

  // Core markets
  const coreMarkets = ['SD','EG','CD','ZM','CI','SA','AE'];
  const isCore = coreMarkets.includes(country);

  let priority = 4;

/**
 * 小满CRM — 会话分类引擎
 *
 * 将每个会话归类到 11 个类别之一，并分配 S/A/B/C 优先级。
 *
 * 使用方式：
 *   import { classifyConversation } from './classifier.mjs';
 *   const result = classifyConversation(conversation);
 */

// ============================================================
// 分类定义
// ============================================================

export const CATEGORIES = [
  { id: 'awaiting_reply',    label: '待回复',   emoji: '🔴', priority: 'P0', desc: '客户发来消息，我方未回复' },
  { id: 'awaiting_quote',    label: '待报价',   emoji: '🟠', priority: 'P0', desc: '客户询盘，未正式报价' },
  { id: 'negotiating',       label: '谈判中',   emoji: '💬', priority: 'P0', desc: '正讨论价格/条款/细节' },
  { id: 'after_sales',       label: '售后处理', emoji: '⚠️', priority: 'P0', desc: '质量投诉、退换货' },
  { id: 'sample_request',    label: '待寄样',   emoji: '📦', priority: 'P1', desc: '客户要求样品' },
  { id: 'sample_followup',   label: '样品跟进', emoji: '🔬', priority: 'P1', desc: '样品已寄出，等反馈' },
  { id: 'awaiting_payment',  label: '待付款',   emoji: '🟡', priority: 'P1', desc: 'PI已发，等付款' },
  { id: 'awaiting_delivery', label: '待发货',   emoji: '🟢', priority: 'P1', desc: '已收款，未发货' },
