  if (negotiateKw.some(k => content.includes(k)) && daysAgo < 7) return '谈判中';

  if (msgCount <= 5 && daysAgo < 14) return '初询阶段';
  if (daysAgo >= 30) return '沉默->30d';
  if (daysAgo >= 7 && daysAgo < 30) return '待激活';

  return '';
}

// === HELPERS ===
function daysAgoFn(ts) { if (!ts) return 9999; return Math.floor((NOW_TS - ts) / D); }
function fmtDate(ts) { if (!ts) return ''; return new Date(ts).toISOString().slice(0, 10); }
function cidToFile(cid) { return cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : ''; }

// === MAIN ===
async function main() {
  console.log('[CRM Tracker] Reading data...');

  // 1. Conversations
  if (!fs.existsSync(TM_FILE)) { console.error('tm_conversations_latest.json not found'); process.exit(1); }
  const tmData = JSON.parse(fs.readFileSync(TM_FILE, 'utf8'));
  const convs = tmData.conversations || [];
  console.log(`  ${convs.length} conversations`);

  // 2. Customers (name-based lookup)
  const customerFiles = fs.readdirSync(CUSTOMERS_DIR).filter(f => f.endsWith('.json'));
  const custByName = {};
  for (const f of customerFiles) {
    try {
      const raw = fs.readFileSync(path.join(CUSTOMERS_DIR, f), 'utf8');
      const cust = JSON.parse(raw);
      const name = (cust.name || cust.detail?.name_info || '').toLowerCase().trim();
      if (name) {
        custByName[name] = {
          okkiLevel: cust.listData?.level || cust.detail?.cus_tag_info?.[0]?.info_label || '',
          okkiStatus: cust.listData?.status || cust.detail?.trail_status_info || '',
          country: cust.listData?.country || cust.detail?.country || '',
          intent: cust.detail?.intention_level_info || '',
        };
      }
    } catch (e) { /* skip */ }
  }
  console.log(`  ${Object.keys(custByName).length} customer profiles matched`);

  // 3. Chat message counts (fast scan)
  const chatDirFiles = fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json'));
  const chatMsgCount = {};
  for (const cf of chatDirFiles) {
    try {
      const raw = fs.readFileSync(path.join(CHAT_DIR, cf), 'utf8');
      const match = raw.match(/"totalMessages":\s*(\d+)/);
      if (match) chatMsgCount[cf] = parseInt(match[1]);
    } catch (e) { /* skip */ }
  }

  // 4. Existing P0/P1 names from STATE.md for override
  const knownP0P1 = new Map();
  if (fs.existsSync(STATE_FILE)) {
    const sc = fs.readFileSync(STATE_FILE, 'utf8');
    const tierSec = sc.match(/\|\s*\*\*(P\d)\*\*[^\n]*\n/g);
    if (tierSec) {
      for (const line of tierSec) {
        const m = line.match(/\*\*(P\d)\*\*\s+\S+\s+\|\s+\*?\*?(\d+)\*?\*?\s*\|?\s*(.+)/);
        if (m) {
          const tier = m[1];
          const names = m[3].split(/[,，、]/);
          for (const n of names) {
            const trimmed = n.trim().replace(/\(.*\)/g, '').trim();
            if (trimmed && !trimmed.startsWith('等') && !/^\d+$/.test(trimmed)) {
              knownP0P1.set(trimmed.toLowerCase(), tier);
            }
          }
        }
      }
    }
  }
  console.log(`  ${knownP0P1.size} known P0/P1 from STATE.md`);

  // 5. Build rows
  const rows = [];
  for (const conv of convs) {
    const filename = cidToFile(conv.cid);
    const msgCount = filename ? (chatMsgCount[filename] || 0) : 0;
    const nameLow = (conv.name || '').toLowerCase().trim();

    // Match customer profile
    let cust = custByName[nameLow] || null;
    if (!cust) {
      for (const [cn, ci] of Object.entries(custByName)) {
        if (nameLow.includes(cn) || cn.includes(nameLow)) { cust = ci; break; }
      }
    }

    // Tier: STATE.md overrides auto-classification
    let tier = '';
    for (const [kn, kv] of knownP0P1) {
      if (nameLow.includes(kn) || kn.includes(nameLow)) { tier = kv; break; }
    }
    if (!tier) tier = classifyTier(conv, msgCount);

    // Stage
    const stage = detectStage(conv, msgCount);

    // Direction
    let lastMsgDir = '';
    if (conv.latestMessage) {
      lastMsgDir = conv.latestMessage.messageType === 'send' ? '我方' : '客户';
    }

    const d = daysAgoFn(conv.lastContactTime);

    rows.push({
      name: conv.name || '',
      countryCode: conv.complianceCountryCode || '',
      countryCN: cn(conv.complianceCountryCode),
      tier,
      okkiLevel: cust ? cust.okkiLevel : '',
      okkiStatus: cust ? cust.okkiStatus : '',
      lastContactDays: d,
      lastContactDate: fmtDate(conv.lastContactTime),
      msgCount,
      lastMsgDir,
      unreadCount: conv.unreadCount || 0,
      stage,
      bottleneck: '',
      nextAction: '',
      followupPriority: tier === 'P0' ? '今天' : tier === 'P1' ? '48h' : tier === 'P2' ? '本周' : '',
      notes: cust && cust.intent && cust.intent !== '未知' ? `意向:${cust.intent}` : '',
      cid: conv.cid,
      filename,
    });
  }

  // Sort: P0 → P1 → P2 → P3 → P4, then by lastContactDays asc within each
  const tierOrder = { P0: 0, P1: 1, P2: 2, P3: 3, P4: 4 };
  rows.sort((a, b) => {
    const ta = tierOrder[a.tier] ?? 5;
    const tb = tierOrder[b.tier] ?? 5;
    if (ta !== tb) return ta - tb;
    return a.lastContactDays - b.lastContactDays;
  });

  // === GEN EXCEL ===
  console.log(`[CRM Tracker] Generating ${rows.length} rows...`);

  const wb = new ExcelJS.Workbook();
  wb.creator = 'OKKI CRM Tracker';
  wb.created = NOW;

  const ws = wb.addWorksheet('客户管理看板', { views: [{ state: 'frozen', ySplit: 1 }] });

  const cols = [
    { header: '客户名', key: 'name', width: 24 },
    { header: '国家', key: 'countryCN', width: 12 },
    { header: '梯队', key: 'tier', width: 7 },
    { header: '小满等级', key: 'okkiLevel', width: 14 },
    { header: '小满状态', key: 'okkiStatus', width: 12 },
    { header: '最后联系\n(天前)', key: 'lastContactDays', width: 9 },
    { header: '最后联系日期', key: 'lastContactDate', width: 13 },
    { header: '总消息', key: 'msgCount', width: 8 },
    { header: '最新', key: 'lastMsgDir', width: 7 },
    { header: '未读', key: 'unreadCount', width: 6 },
    { header: '沟通阶段', key: 'stage', width: 18 },
    { header: '卡点', key: 'bottleneck', width: 28 },
    { header: '下一步行动', key: 'nextAction', width: 34 },
    { header: '跟紧', key: 'followupPriority', width: 8 },
    { header: '备注', key: 'notes', width: 22 },
  ];
  ws.columns = cols;

  // Header style
  const hr = ws.getRow(1);
  hr.font = { bold: true, size: 11, color: { argb: 'FFFFFFFF' } };
  hr.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
  hr.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
  hr.height = 34;

  const tierFills = {
    P0: 'FFC00000', P1: 'FFED7D31', P2: 'FFFFC000', P3: 'FF4472C4', P4: 'FFA5A5A5',
  };

  for (const row of rows) {
    const r = ws.addRow(row);
    r.height = 21;

    // Tier color
    if (row.tier && tierFills[row.tier]) {
      const tc = r.getCell('tier');
      tc.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 11 };
      tc.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: tierFills[row.tier] } };
      tc.alignment = { horizontal: 'center' };
    }

    // Faded for >30d
    if (row.lastContactDays > 30) r.font = { color: { argb: 'FFA0A0A0' } };
    // Unread highlight
    if (row.unreadCount > 0) r.getCell('unreadCount').font = { bold: true, color: { argb: 'FFC00000' } };
    // Stage bold
    if (row.stage) r.getCell('stage').font = { bold: true };
    // P0 name bold
    if (row.tier === 'P0') r.getCell('name').font = { bold: true };
  }

  ws.autoFilter = { from: { row: 1, column: 1 }, to: { row: rows.length + 1, column: cols.length } };

  // === SUMMARY SHEET ===
  const sws = wb.addWorksheet('统计');
  sws.columns = [
    { header: '指标', key: 'metric', width: 22 },
    { header: '数值', key: 'value', width: 26 },
  ];

  const tc = { P0: 0, P1: 0, P2: 0, P3: 0, P4: 0, '未分类': 0 };
  for (const r of rows) {
    if (r.tier && tc[r.tier] !== undefined) tc[r.tier]++;
    else tc['未分类']++;
  }

  const a24 = rows.filter(r => r.lastContactDays < 1).length;
  const a7d = rows.filter(r => r.lastContactDays < 7).length;
  const a30d = rows.filter(r => r.lastContactDays < 30).length;
  const s30d = rows.filter(r => r.lastContactDays >= 30).length;
  const withStage = rows.filter(r => r.stage).length;
  const withBN = rows.filter(r => r.bottleneck).length;

  sws.addRows([
    { metric: '生成时间', value: NOW.toISOString().slice(0, 16).replace('T', ' ') },
    { metric: '数据导出时间', value: tmData.exportedAt ? new Date(tmData.exportedAt).toISOString().slice(0, 16).replace('T', ' ') : '' },
    { metric: '客户总数', value: rows.length },
    { metric: '24h活跃', value: a24 },
    { metric: '7d活跃', value: a7d },
    { metric: '30d内活跃', value: a30d },
    { metric: '>30d沉默', value: s30d },
    { metric: '', value: '' },
    ...Object.entries(tc).map(([k, v]) => ({ metric: `梯队 ${k}`, value: v })),
    { metric: '', value: '' },
    { metric: '已推断阶段', value: withStage },
    { metric: '已标注卡点', value: withBN },
    { metric: '待AI深度分析', value: rows.length - withBN },
    { metric: '', value: '' },
    { metric: '分类规则', value: 'P0=未读/客户最新消息/PI关键词 | P1=7d活跃+≥5条 | P2=7d活跃 | P3=<30d | P4=>30d静默' },
  ]);

  const sh = sws.getRow(1);
  sh.font = { bold: true, color: { argb: 'FFFFFFFF' } };
  sh.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };

  const outFile = path.join(REPORTS_DIR, `客户管理看板_${DATE_STR}.xlsx`);
  if (!fs.existsSync(REPORTS_DIR)) fs.mkdirSync(REPORTS_DIR, { recursive: true });
  await wb.xlsx.writeFile(outFile);

  console.log(`\n[Done] ${outFile}`);
  console.log(`  ${rows.length} customers | P0:${tc.P0} P1:${tc.P1} P2:${tc.P2} P3:${tc.P3} P4:${tc.P4}`);
  console.log(`  24h:${a24} | 7d:${a7d} | 30d:${a30d} | >30d:${s30d}`);
  console.log(`  Stage detected: ${withStage} | Need AI: ${rows.length - withBN}`);
}

main().catch(err => { console.error(err); process.exit(1); });
